def process_transactions(transactions, accounts):
    """
    Processes financial transactions and updates account balances.

    Args:
        transactions: A list of transactions, where each transaction is a dictionary with keys 'account', 'amount', and 'type'.
        accounts: A dictionary of account balances, where each account is a key and the balance is the value.

    Returns:
        A dictionary of updated account balances.
    """

    for transaction in transactions:
        account = transaction['account']
        amount = transaction['amount']
        transaction_type = transaction['type']

        if transaction_type == 'deposit':
            accounts[account] += amount
        elif transaction_type == 'withdrawal':
            accounts[account] -= amount
        else:
            raise ValueError('Invalid transaction type.')

    return accounts